import React, { useEffect, useState } from 'react';
import './profile.css';
import Image from './phonk_wallpaper.jpg';
import { useNavigate } from "react-router-dom";

function ProfilePage() {
  const [profile, setProfile] = useState(null);
  const navigate = useNavigate();

  useEffect(() => {
    async function loadProfile() {
      const token = localStorage.getItem("access");

      if (!token) {
        console.log("Нет токена — пользователь не авторизован");
        return;
      }

      try {
        const response = await fetch("http://localhost:8000/api/user/", {
          method: "GET",
          headers: {
            Authorization: `Bearer ${token}`
          }
        });

        if (!response.ok) {
          console.log("Ошибка загрузки профиля");
          return;
        }

        const data = await response.json();
        setProfile(data);

      } catch (error) {
        console.error("Ошибка запроса:", error);
      }
    }

    loadProfile();
  }, []);

  function logout() {
    localStorage.removeItem("access");
    localStorage.removeItem("refresh");
    setProfile(null);
    navigate("/login");
  }

  return (
    <div id="content">
      <div id="info_card">
        <p id="info_card_name">Информация о пользователе</p>

        <p id="info_card_text">
          {profile
            ? `User: ${profile.username}`
            : "Нету данных..."}
          <br/> 
          {profile
            ? `Имя: ${profile.first_name}`
            : "Нету данных..."}
          <br/> 
          {profile
            ? `Фамилия: ${profile.last_name}`
            : "Нету данных..."}
        </p>
        
        <button id="logout_button" onClick={logout}>
          Выйти из аккаунта
        </button>
      </div>

      <div id="friends_card">
        <div id="friend_card">
          <img src={Image} alt="Ну нету авы, я что сделаю!" id="friends_card_img" />
          <p id="friends_card_text">? ? ?</p>
        </div>

        <div id="friend_card">
          <img src={Image} alt="Ну нету авы, я что сделаю!" id="friends_card_img" />
          <p id="friends_card_text">? ? ?</p>
        </div>

        <div id="friend_card">
          <img src={Image} alt="Ну нету авы, я что сделаю!" id="friends_card_img" />
          <p id="friends_card_text">? ? ?</p>
        </div>

        <div id="friend_card">
          <img src={Image} alt="Ну нету авы, я что сделаю!" id="friends_card_img" />
          <p id="friends_card_text">? ? ?</p>
        </div>
      </div>

      <div id="purchase_history_card">
        <div id="operation_card">
          <p id="operation_card_text">? ? ?</p>
          <p id="operation_card_price">Цена: ? ? ?</p>
        </div>

        <div id="operation_card">
          <p id="operation_card_text">? ? ?</p>
          <p id="operation_card_price">Цена: ? ? ?</p>
        </div>

        <div id="operation_card">
          <p id="operation_card_text">? ? ?</p>
          <p id="operation_card_price">Цена: ? ? ?</p>
        </div>
      </div>
    </div>
  );
}

export default ProfilePage;
